'use client';

/**
 * Chat Button Component
 * 画面右下に固定配置される円形のチャットアイコンボタン
 */

import { useState, useEffect } from 'react';
import { detectBrowserLocale, getMessages } from '@/client/lib/theme/i18n';

interface ChatButtonProps {
  onClick: () => void;
}

export function ChatButton({ onClick }: ChatButtonProps) {
  // ロケール検出：クライアントサイドでのみ実行
  const [openChatLabel, setOpenChatLabel] = useState('チャットを開く');

  useEffect(() => {
    const locale = detectBrowserLocale();
    const messages = getMessages(locale);
    setOpenChatLabel(messages.openChat);
  }, []);

  return (
    <button
      onClick={onClick}
      className="fixed bottom-5 right-5 z-[1000]
                 w-[60px] h-[60px] md:w-[70px] md:h-[70px]
                 rounded-full
                 bg-[#ed1c2a]
                 shadow-lg hover:shadow-xl
                 flex items-center justify-center
                 transition-transform duration-200 ease-out
                 hover:scale-110
                 focus:outline-none focus:ring-4 focus:ring-red-300"
      aria-label={openChatLabel}
    >
      <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 24 24"
        fill="white"
        className="w-8 h-8 md:w-9 md:h-9"
      >
        {/* 吹き出し本体 */}
        <path d="M12 3C6.5 3 2 6.58 2 11c0 2.05.92 3.91 2.43 5.32.14.13.23.31.23.51 0 .97-.52 1.86-1.05 2.57-.15.2-.08.49.16.56.68.19 1.75.33 2.91-.16 1.07-.45 1.92-.45 2.32-.45C14 19.35 22 16.08 22 11c0-4.42-4.5-8-10-8z" />
        {/* 3つのドット */}
        <circle cx="8" cy="11" r="1.2" fill="#ed1c2a" />
        <circle cx="12" cy="11" r="1.2" fill="#ed1c2a" />
        <circle cx="16" cy="11" r="1.2" fill="#ed1c2a" />
      </svg>
    </button>
  );
}

