/**
 * Unit Test: i18n (Internationalization)
 * タスク6.2: クライアントサイド単体テスト
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { detectBrowserLocale, getMessages, type SupportedLocale } from '@/client/lib/theme/i18n';

describe('i18n (Internationalization)', () => {
  describe('detectBrowserLocale', () => {
    let originalNavigator: Navigator;

    beforeEach(() => {
      originalNavigator = global.navigator;
    });

    afterEach(() => {
      global.navigator = originalNavigator;
    });

    it('日本語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'ja-JP',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('ja');
    });

    it('英語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'en-US',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('en');
    });

    it('中国語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'zh-CN',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('zh');
    });

    it('韓国語ブラウザを検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'ko-KR',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('ko');
    });

    it('サポート外の言語はデフォルト（ja）にフォールバックする', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'fr-FR',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('ja');
    });

    it('大文字小文字を区別せず検知する', () => {
      Object.defineProperty(global.navigator, 'language', {
        writable: true,
        value: 'EN-US',
      });

      const locale = detectBrowserLocale();
      expect(locale).toBe('en');
    });
  });

  describe('getMessages', () => {
    it('日本語メッセージを取得する', () => {
      const messages = getMessages('ja');

      expect(messages.placeholder).toBe('メッセージを入力してください');
      expect(messages.send).toBe('送信');
      expect(messages.loading).toBe('応答を生成中...');
      expect(messages.error).toBe('エラーが発生しました');
      expect(messages.retry).toBe('再試行');
      expect(messages.charLimitError).toBe('256文字以内で入力してください');
      expect(messages.piiError).toBe('個人情報は入力しないでください');
      expect(messages.welcome).toBe(
        'こんにちは！ワールドマスターズゲームズ2027関西のサポートチャットです 🎉\n大会に関するご質問にAIがお答えします。\nメッセージを入力してください。'
      );
    });

    it('英語メッセージを取得する', () => {
      const messages = getMessages('en');

      expect(messages.placeholder).toBe('Enter your message');
      expect(messages.send).toBe('Send');
      expect(messages.loading).toBe('Generating response...');
      expect(messages.error).toBe('An error occurred');
      expect(messages.retry).toBe('Retry');
      expect(messages.charLimitError).toBe('Please enter within 256 characters');
      expect(messages.piiError).toBe('Please do not enter personal information');
      expect(messages.welcome).toBe(
        'Hello! Welcome to World Masters Games 2027 Kansai Support Chat 🎉\nOur AI will answer your questions about the games.\nPlease enter your message.'
      );
    });

    it('中国語メッセージを取得する', () => {
      const messages = getMessages('zh');

      expect(messages.placeholder).toBe('请输入消息');
      expect(messages.send).toBe('发送');
      expect(messages.loading).toBe('正在生成回复...');
      expect(messages.error).toBe('发生错误');
      expect(messages.retry).toBe('重试');
      expect(messages.charLimitError).toBe('请在256个字符以内输入');
      expect(messages.piiError).toBe('请勿输入个人信息');
      expect(messages.welcome).toBe(
        '您好！欢迎使用2027年世界大师运动会关西支持聊天 🎉\nAI将回答您关于大会的问题。\n请输入您的消息。'
      );
    });

    it('韓国語メッセージを取得する', () => {
      const messages = getMessages('ko');

      expect(messages.placeholder).toBe('메시지를 입력하세요');
      expect(messages.send).toBe('전송');
      expect(messages.loading).toBe('응답 생성 중...');
      expect(messages.error).toBe('오류가 발생했습니다');
      expect(messages.retry).toBe('재시도');
      expect(messages.charLimitError).toBe('256자 이내로 입력해주세요');
      expect(messages.piiError).toBe('개인정보를 입력하지 마세요');
      expect(messages.welcome).toBe(
        '안녕하세요! 2027 월드마스터즈게임 간사이 지원 챗봇입니다 🎉\nAI가 대회에 관한 질문에 답변해 드립니다.\n메시지를 입력해 주세요.'
      );
    });

    it('すべてのロケールで必須メッセージキーが存在する', () => {
      const locales: SupportedLocale[] = ['ja', 'en', 'zh', 'ko'];
      const requiredKeys: (keyof ReturnType<typeof getMessages>)[] = [
        'placeholder',
        'send',
        'loading',
        'error',
        'retry',
        'charLimitError',
        'piiError',
        'welcome',
        // UI text keys
        'headerTitle',
        'headerSubtitle',
        'closeChat',
        'openChat',
        'disclaimer1',
        'disclaimer2',
        'disclaimer3',
      ];

      for (const locale of locales) {
        const messages = getMessages(locale);
        for (const key of requiredKeys) {
          expect(messages[key]).toBeDefined();
          expect(messages[key].length).toBeGreaterThan(0);
        }
      }
    });
  });

  describe('UI text i18n', () => {
    it('日本語UIテキストを取得する', () => {
      const messages = getMessages('ja');

      expect(messages.headerTitle).toBe('WMG2027 サポートチャット');
      expect(messages.headerSubtitle).toBe('お気軽にご質問ください');
      expect(messages.closeChat).toBe('チャットを閉じる');
      expect(messages.openChat).toBe('チャットを開く');
      expect(messages.disclaimer1).toBe('お申込みのヒントとして、AIが皆さまをサポートいたします。');
      expect(messages.disclaimer2).toBe(
        'まだ勉強中のため、たまに間違ったお答えをしてしまうことがあるかもしれません。'
      );
      expect(messages.disclaimer3).toBe(
        '大切なルールや締切については、念のため大会要項もチェックしながら進めていただけると安心です！'
      );
    });

    it('英語UIテキストを取得する', () => {
      const messages = getMessages('en');

      expect(messages.headerTitle).toBe('WMG2027 Support Chat');
      expect(messages.headerSubtitle).toBe('Feel free to ask');
      expect(messages.closeChat).toBe('Close Chat');
      expect(messages.openChat).toBe('Open Chat');
      expect(messages.disclaimer1).toBe('Our AI assistant is here to help with your registration.');
      expect(messages.disclaimer2).toBe(
        "It's still learning, so it may sometimes give incorrect answers."
      );
      expect(messages.disclaimer3).toBe(
        'For critical rules or deadlines, always refer to the official competition guidelines.'
      );
    });

    it('日本語以外のロケール（zh）は英語UIテキストを使用する', () => {
      const messages = getMessages('zh');

      expect(messages.headerTitle).toBe('WMG2027 Support Chat');
      expect(messages.headerSubtitle).toBe('Feel free to ask');
      expect(messages.closeChat).toBe('Close Chat');
      expect(messages.openChat).toBe('Open Chat');
      expect(messages.disclaimer1).toBe('Our AI assistant is here to help with your registration.');
    });

    it('日本語以外のロケール（ko）は英語UIテキストを使用する', () => {
      const messages = getMessages('ko');

      expect(messages.headerTitle).toBe('WMG2027 Support Chat');
      expect(messages.headerSubtitle).toBe('Feel free to ask');
      expect(messages.closeChat).toBe('Close Chat');
      expect(messages.openChat).toBe('Open Chat');
      expect(messages.disclaimer1).toBe('Our AI assistant is here to help with your registration.');
    });
  });
});

