/**
 * ChatWindow Component Unit Tests
 * Issue #112: Chat UIテスト追加
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { ChatWindow } from '@/client/components/chat/ChatWindow';

// Mock useChat hook from ai/react
vi.mock('ai/react', () => ({
  useChat: vi.fn(() => ({
    messages: [],
    input: '',
    setInput: vi.fn(),
    handleSubmit: vi.fn(),
    isLoading: false,
    error: null,
    reload: vi.fn(),
  })),
}));

// Mock i18n
vi.mock('@/client/lib/theme/i18n', () => ({
  detectBrowserLocale: vi.fn(() => 'ja'),
  getMessages: vi.fn(() => ({
    welcome: 'こんにちは！WMG2027に関するご質問をどうぞ。',
    error: 'エラーが発生しました',
    retry: '再試行',
  })),
}));

// Mock child components to simplify testing
vi.mock('@/client/components/chat/ChatMessage', () => ({
  ChatMessage: ({ message }: { message: { id: string; content: string } }) => (
    <div data-testid={`message-${message.id}`}>{message.content}</div>
  ),
  ChatLoadingIndicator: () => <div data-testid="loading-indicator">Loading...</div>,
}));

vi.mock('@/client/components/chat/ChatInput', () => ({
  ChatInput: ({
    input,
    isLoading,
    onInputChange,
    onSubmit,
  }: {
    input: string;
    isLoading: boolean;
    onInputChange: (v: string) => void;
    onSubmit: () => void;
  }) => (
    <div data-testid="chat-input">
      <input
        data-testid="input"
        value={input}
        onChange={e => onInputChange(e.target.value)}
        disabled={isLoading}
      />
      <button data-testid="submit" onClick={onSubmit} disabled={isLoading}>
        送信
      </button>
    </div>
  ),
}));

describe('ChatWindow Component', () => {
  const mockOnClose = vi.fn();

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('Visibility', () => {
    it('should not render when isOpen is false', () => {
      const { container } = render(<ChatWindow isOpen={false} onClose={mockOnClose} />);

      expect(container.firstChild).toBeNull();
    });

    it('should render when isOpen is true', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByRole('dialog')).toBeInTheDocument();
    });
  });

  describe('Header', () => {
    it('should display title', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByText('WMG2027 サポートチャット')).toBeInTheDocument();
    });

    it('should display subtitle', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByText('お気軽にご質問ください')).toBeInTheDocument();
    });

    it('should have close button', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByRole('button', { name: 'チャットを閉じる' })).toBeInTheDocument();
    });

    it('should call onClose when close button is clicked', async () => {
      const user = userEvent.setup();
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      const closeButton = screen.getByRole('button', { name: 'チャットを閉じる' });
      await user.click(closeButton);

      expect(mockOnClose).toHaveBeenCalledTimes(1);
    });

    it('should display WMG logo in header', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      const logos = screen.getAllByAltText('WMG2027 Logo');
      expect(logos.length).toBeGreaterThan(0);
    });
  });

  describe('Welcome Message', () => {
    it('should display welcome message when no messages', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByText('こんにちは！WMG2027に関するご質問をどうぞ。')).toBeInTheDocument();
    });
  });

  describe('Message Display', () => {
    it('should render messages from useChat', async () => {
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [
          { id: 'msg-1', role: 'user', content: 'ユーザーメッセージ' },
          { id: 'msg-2', role: 'assistant', content: 'アシスタント応答' },
        ],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: false,
        error: null,
        reload: vi.fn(),
      } as any);

      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByTestId('message-msg-1')).toBeInTheDocument();
      expect(screen.getByTestId('message-msg-2')).toBeInTheDocument();
    });

    it('should not show welcome message when there are messages', async () => {
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [{ id: 'msg-1', role: 'user', content: 'Hello' }],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: false,
        error: null,
        reload: vi.fn(),
      } as any);

      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(
        screen.queryByText('こんにちは！WMG2027に関するご質問をどうぞ。')
      ).not.toBeInTheDocument();
    });
  });

  describe('Loading State', () => {
    it('should show loading indicator when isLoading is true', async () => {
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: true,
        error: null,
        reload: vi.fn(),
      } as any);

      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByTestId('loading-indicator')).toBeInTheDocument();
    });

    it('should not show loading indicator when isLoading is false', async () => {
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: false,
        error: null,
        reload: vi.fn(),
      } as any);

      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.queryByTestId('loading-indicator')).not.toBeInTheDocument();
    });
  });

  describe('Error Handling', () => {
    it('should display error message when error occurs', async () => {
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: false,
        error: new Error('Network error'),
        reload: vi.fn(),
      } as any);

      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByText('エラーが発生しました')).toBeInTheDocument();
      expect(screen.getByText('Network error')).toBeInTheDocument();
    });

    it('should show retry button on error', async () => {
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: false,
        error: new Error('Network error'),
        reload: vi.fn(),
      } as any);

      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByText('再試行')).toBeInTheDocument();
    });

    it('should call reload when retry button is clicked', async () => {
      const mockReload = vi.fn();
      const { useChat } = await import('ai/react');
      vi.mocked(useChat).mockReturnValue({
        messages: [],
        input: '',
        setInput: vi.fn(),
        handleSubmit: vi.fn(),
        isLoading: false,
        error: new Error('Network error'),
        reload: mockReload,
      } as any);

      const user = userEvent.setup();
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      const retryButton = screen.getByText('再試行');
      await user.click(retryButton);

      expect(mockReload).toHaveBeenCalledTimes(1);
    });
  });

  describe('Mobile Overlay', () => {
    it('should close when overlay is clicked', async () => {
      const user = userEvent.setup();
      const { container } = render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      // Find the overlay (first child with inset-0)
      const overlay = container.querySelector('.inset-0.bg-black\\/50');
      if (overlay) {
        await user.click(overlay);
        expect(mockOnClose).toHaveBeenCalled();
      }
    });
  });

  describe('Accessibility', () => {
    it('should have role="dialog"', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByRole('dialog')).toBeInTheDocument();
    });

    it('should have aria-modal="true"', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByRole('dialog')).toHaveAttribute('aria-modal', 'true');
    });

    it('should have aria-labelledby pointing to title', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      const dialog = screen.getByRole('dialog');
      expect(dialog).toHaveAttribute('aria-labelledby', 'chat-title');
      expect(screen.getByText('WMG2027 サポートチャット')).toHaveAttribute('id', 'chat-title');
    });
  });

  describe('Chat Input Integration', () => {
    it('should render ChatInput component', () => {
      render(<ChatWindow isOpen={true} onClose={mockOnClose} />);

      expect(screen.getByTestId('chat-input')).toBeInTheDocument();
    });
  });
});

