'use client';

/**
 * Chat Message Component
 * ユーザーとボットのメッセージ表示（Markdownサポート）
 */

import { Message } from 'ai';
import ReactMarkdown from 'react-markdown';

interface ChatMessageProps {
  message: Message;
}

export function ChatMessage({ message }: ChatMessageProps) {
  const isUser = message.role === 'user';
  const timestamp = new Date().toLocaleTimeString('ja-JP', {
    hour: '2-digit',
    minute: '2-digit',
  });

  if (isUser) {
    return (
      <div className="flex justify-end items-end mb-4 animate-slideIn">
        <div className="flex flex-col items-end max-w-[75%] md:max-w-[70%] sm:max-w-[80%]">
          <div className="bg-[#FFF0F0] text-[#333333] rounded-2xl rounded-br-md px-4 py-3">
            <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
              {message.content}
            </p>
          </div>
          <span className="text-xs text-gray-400 mt-1 px-1">{timestamp}</span>
        </div>
      </div>
    );
  }

  return (
    <div className="flex justify-start items-start mb-4 animate-slideIn">
      {/* ボットアイコン（WMGロゴ） */}
      <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
        <img
          src="/wmg2027-logo.png"
          alt="WMG2027 Logo"
          className="w-full h-full object-cover object-[center_65%]"
        />
      </div>

      {/* メッセージ（Markdownレンダリング） */}
      <div className="flex flex-col items-start max-w-[75%] md:max-w-[70%] sm:max-w-[80%]">
        <div className="bg-white text-[#333333] rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
          <div className="text-sm md:text-[15px] leading-relaxed prose prose-sm max-w-none prose-a:text-blue-600 prose-a:underline hover:prose-a:text-blue-800">
            <ReactMarkdown
              components={{
                a: ({ href, children }) => (
                  <a
                    href={href}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 underline hover:text-blue-800"
                  >
                    {children}
                  </a>
                ),
                p: ({ children }) => <p className="mb-2 last:mb-0">{children}</p>,
                ul: ({ children }) => <ul className="list-disc list-inside mb-2">{children}</ul>,
                ol: ({ children }) => <ol className="list-decimal list-inside mb-2">{children}</ol>,
                li: ({ children }) => <li className="mb-1">{children}</li>,
              }}
            >
              {message.content}
            </ReactMarkdown>
          </div>
        </div>
        <span className="text-xs text-gray-400 mt-1 px-1">{timestamp}</span>
      </div>
    </div>
  );
}

/**
 * Loading Indicator Component
 * ボット返信中の「入力中...」アニメーション
 */
export function ChatLoadingIndicator() {
  return (
    <div className="flex justify-start items-start mb-4">
      {/* ボットアイコン（WMGロゴ） */}
      <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
        <img
          src="/wmg2027-logo.png"
          alt="WMG2027 Logo"
          className="w-full h-full object-cover object-[center_65%]"
        />
      </div>

      {/* ローディングメッセージ */}
      <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
        <div className="flex items-center space-x-1">
          <div
            className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"
            style={{ animationDelay: '0ms' }}
          ></div>
          <div
            className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"
            style={{ animationDelay: '150ms' }}
          ></div>
          <div
            className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"
            style={{ animationDelay: '300ms' }}
          ></div>
        </div>
      </div>
    </div>
  );
}

'use client';

