  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    // IME変換中はEnterキーを無視
    if (e.key === 'Enter' && !e.shiftKey && !isComposing) {
      e.preventDefault();
      if (input.trim() && !isLoading) {
        onSubmit();
      }
    }
  };

  const handleCompositionStart = () => {
    setIsComposing(true);
  };

  const handleCompositionEnd = () => {
    setIsComposing(false);
  };

  return (
    <div className="border-t border-gray-200 bg-white px-4 py-3 md:px-4 md:py-4">
      {/* 入力エリア */}
      <div className="flex items-center space-x-2 md:space-x-2">
        <div className="flex-1 relative">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={e => onInputChange(e.target.value)}
            onKeyDown={handleKeyDown}
            onCompositionStart={handleCompositionStart}
            onCompositionEnd={handleCompositionEnd}
            placeholder={messages_i18n.placeholder}
            disabled={isLoading}
            rows={1}
            className="w-full px-4 py-3
                     border border-[#DDDDDD] rounded-[24px]
                     text-sm md:text-[15px] text-[#333333] placeholder:text-[#999999]
                     resize-none overflow-y-auto
                     focus:outline-none focus:ring-2 focus:ring-[#8B7AB8] focus:border-transparent
                     disabled:bg-gray-100 disabled:text-gray-500
                     transition-all duration-150"
            style={{
              minHeight: `${LINE_HEIGHT + PADDING}px`,
              maxHeight: `${MAX_ROWS * LINE_HEIGHT + PADDING}px`
            }}
          />
        </div>

        {/* 送信ボタン（紫色の円形） */}
        <button
          onClick={onSubmit}
          disabled={!input.trim() || isLoading}
          className="flex-shrink-0 w-12 h-12
                   self-start -mt-1
                   bg-[#8B7AB8]
                   rounded-full
                   flex items-center justify-center
                   transition-all duration-150
                   hover:bg-[#7A6AA7] hover:shadow-md
                   disabled:bg-gray-300 disabled:cursor-not-allowed
                   focus:outline-none focus:ring-2 focus:ring-[#8B7AB8] focus:ring-offset-2"
          aria-label={messages_i18n.send}
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            strokeWidth={2.5}
            stroke="white"
            className="w-6 h-6"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              d="M6 12L3.269 3.126A59.768 59.768 0 0121.485 12 59.77 59.77 0 013.27 20.876L5.999 12zm0 0h7.5"
            />
          </svg>
        </button>
      </div>

      {/* 注意文言（フッター） */}
      <div className="mt-3 px-1 space-y-0.5">
        <p className="text-[10px] text-gray-500 leading-relaxed">
          {messages_i18n.disclaimer1}
        </p>
        <p className="text-[10px] text-gray-500 leading-relaxed">
          {messages_i18n.disclaimer2}
        </p>
        <p className="text-[10px] text-gray-500 leading-relaxed">
          {messages_i18n.disclaimer3}
        </p>
      </div>

      {/* Powered by AI */}
      <div className="mt-2 px-1">
        <p className="text-[10px] text-gray-400 text-right">Powered by AI</p>
      </div>
    </div>
  );
}

'use client';

/**
 * Chat Message Component
 * ユーザーとボットのメッセージ表示（Markdownサポート）
 */

import { Message } from 'ai';
import ReactMarkdown from 'react-markdown';

interface ChatMessageProps {
  message: Message;
}

export function ChatMessage({ message }: ChatMessageProps) {
  const isUser = message.role === 'user';
  const timestamp = new Date().toLocaleTimeString('ja-JP', {
    hour: '2-digit',
    minute: '2-digit',
  });

  if (isUser) {
    return (
      <div className="flex justify-end items-end mb-4 animate-slideIn">
        <div className="flex flex-col items-end max-w-[75%] md:max-w-[70%] sm:max-w-[80%]">
          <div className="bg-[#FFF0F0] text-[#333333] rounded-2xl rounded-br-md px-4 py-3">
            <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
              {message.content}
            </p>
          </div>
          <span className="text-xs text-gray-400 mt-1 px-1">{timestamp}</span>
        </div>
      </div>
    );
  }

  return (
    <div className="flex justify-start items-start mb-4 animate-slideIn">
      {/* ボットアイコン（WMGロゴ） */}
      <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
        <img
          src="/wmg2027-logo.png"
          alt="WMG2027 Logo"
          className="w-full h-full object-cover object-[center_70%]"
        />
      </div>

      {/* メッセージ（Markdownレンダリング） */}
      <div className="flex flex-col items-start max-w-[75%] md:max-w-[70%] sm:max-w-[80%]">
        <div className="bg-white text-[#333333] rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
          <div className="text-sm md:text-[15px] leading-relaxed prose prose-sm max-w-none prose-a:text-blue-600 prose-a:underline hover:prose-a:text-blue-800">
            <ReactMarkdown
              components={{
                a: ({ href, children }) => (
                  <a
                    href={href}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 underline hover:text-blue-800"
                  >
                    {children}
                  </a>
                ),
                p: ({ children }) => <p className="mb-2 last:mb-0">{children}</p>,
                ul: ({ children }) => <ul className="list-disc list-inside mb-2">{children}</ul>,
                ol: ({ children }) => <ol className="list-decimal list-inside mb-2">{children}</ol>,
                li: ({ children }) => <li className="mb-1">{children}</li>,
              }}
            >
              {message.content}
            </ReactMarkdown>
          </div>
        </div>
        <span className="text-xs text-gray-400 mt-1 px-1">{timestamp}</span>
      </div>
    </div>
  );
}

/**
 * Loading Indicator Component
 * ボット返信中の「入力中...」アニメーション
 */
export function ChatLoadingIndicator() {
  return (
    <div className="flex justify-start items-start mb-4">
      {/* ボットアイコン（WMGロゴ） */}
      <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
        <img
          src="/wmg2027-logo.png"
          alt="WMG2027 Logo"
          className="w-full h-full object-cover object-[center_70%]"
        />
      </div>

      {/* ローディングメッセージ */}
      <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
        <div className="flex items-center space-x-1">
          <div
            className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"
            style={{ animationDelay: '0ms' }}
          ></div>
          <div
            className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"
            style={{ animationDelay: '150ms' }}
          ></div>
          <div
            className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"
            style={{ animationDelay: '300ms' }}
          ></div>
        </div>
      </div>
    </div>
  );
}

'use client';

/**
 * Chat Widget Frame
 * タスク4.1: チャットUIシェルとストリーミング入出力
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';
import { clientLogger } from '@/server/lib/logger';

export function ChatWidgetFrame() {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI({
    onError: err => {
      clientLogger.error('Chat error', err);
    },
  });

  return (
    <div className="flex flex-col h-full bg-white rounded-none md:rounded-lg shadow-none md:shadow-lg">
      {/* ヘッダー */}
      <div className="bg-[#E31E24] text-white p-3 md:p-4 rounded-none md:rounded-t-lg relative">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_70%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 className="text-base md:text-lg font-bold leading-tight">
                {messages_i18n.headerTitle}
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                {messages_i18n.headerSubtitle}
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center text-white hover:bg-white/20 rounded-full transition-colors flex-shrink-0"
            aria-label={messages_i18n.closeChat}
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-5 h-5 md:w-6 md:h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
      </div>

      {/* メッセージリスト */}
      <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
        {/* ウェルカムメッセージ */}
        {messages.length === 0 && (
          <div className="mb-4">
            <div className="flex justify-start items-start">
              {/* ボットアイコン（WMGロゴ） */}
              <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                <img
                  src="/wmg2027-logo.png"
                  alt="WMG2027 Logo"
                  className="w-full h-full object-cover object-[center_70%]"
                />
              </div>

              {/* メッセージ */}
              <div className="flex flex-col items-start max-w-[85%]">
                <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                  <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                    {messages_i18n.welcome}
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* メッセージ表示（ChatMessageコンポーネントを使用） */}
        {messages.map(message => (
          <ChatMessage key={message.id} message={message} />
        ))}

        {/* ローディング表示（ChatLoadingIndicatorを使用） */}
        {isLoading && <ChatLoadingIndicator />}

        {/* エラー表示 */}
        {error && (
          <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
            <p className="font-semibold">{messages_i18n.error}</p>
            <p className="text-sm mt-1">{error.message}</p>
            <button onClick={() => reload()} className="mt-2 text-sm underline hover:no-underline">
              {messages_i18n.retry}
            </button>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* 入力エリア */}
      <div className="flex-shrink-0">
        <ChatInput
          input={input}
          isLoading={isLoading}
          onInputChange={handleInputChange}
          onSubmit={handleFormSubmit}
          messages_i18n={messages_i18n}
        />
      </div>
    </div>
  );
}

'use client';

/**
 * Chat Window Component
 * チャットウィンドウ全体（ヘッダー、メッセージ表示エリア、入力エリア）
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';

interface ChatWindowProps {
  isOpen: boolean;
  onClose: () => void;
}

export function ChatWindow({ isOpen, onClose }: ChatWindowProps) {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI();

  if (!isOpen) return null;

  return (
    <>
      {/* モバイル用オーバーレイ（768px未満） */}
      <div
        className="fixed inset-0 bg-black/50 z-[1000] md:hidden animate-fadeIn"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* チャットウィンドウ */}
      <div
        className={`
          fixed z-[1001]
          flex flex-col
          bg-white
          shadow-2xl

          /* モバイル: 全画面表示 */
          bottom-0 left-0 right-0 top-0
          w-full h-full
          animate-slideUpMobile

          /* PC: 右下固定表示 */
          md:bottom-5 md:right-5 md:left-auto md:top-auto
          md:w-[400px] md:h-[600px]
          md:rounded-2xl
          md:animate-slideInDesktop
        `}
        role="dialog"
        aria-labelledby="chat-title"
        aria-modal="true"
      >
        {/* ヘッダー */}
        <div className="bg-[#E31E24] text-white px-4 py-3 md:py-4 flex items-center justify-between flex-shrink-0 md:rounded-t-2xl">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_70%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 id="chat-title" className="text-base md:text-lg font-bold leading-tight">
                {messages_i18n.headerTitle}
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                {messages_i18n.headerSubtitle}
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            onClick={onClose}
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center rounded-full hover:bg-white/20 transition-colors focus:outline-none focus:ring-2 focus:ring-white/50"
            aria-label={messages_i18n.closeChat}
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-6 h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* メッセージ表示エリア */}
        <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
          {/* ウェルカムメッセージ */}
          {messages.length === 0 && (
            <div className="mb-4">
              <div className="flex justify-start items-start">
                {/* ボットアイコン（WMGロゴ） */}
                <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                  <img
                    src="/wmg2027-logo.png"
                    alt="WMG2027 Logo"
                    className="w-full h-full object-cover object-[center_70%]"
                  />
                </div>

                {/* メッセージ */}
                <div className="flex flex-col items-start max-w-[85%]">
                  <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                    <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                      {messages_i18n.welcome}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* メッセージリスト */}
          {messages.map(message => (
            <ChatMessage key={message.id} message={message} />
          ))}

          {/* ローディングインジケータ */}
          {isLoading && <ChatLoadingIndicator />}

          {/* エラー表示 */}
          {error && (
            <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
              <p className="font-semibold">{messages_i18n.error}</p>
              <p className="text-sm mt-1">{error.message}</p>
              <button
                onClick={() => reload()}
                className="mt-2 text-sm underline hover:no-underline"
              >
                {messages_i18n.retry}
              </button>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* 入力エリア */}
        <div className="flex-shrink-0">
          <ChatInput
            input={input}
            isLoading={isLoading}
            onInputChange={handleInputChange}
            onSubmit={handleFormSubmit}
            messages_i18n={messages_i18n}
          />
        </div>
      </div>
    </>
  );
}

