'use client';

/**
 * Chat Input Component
 * メッセージ入力エリアと送信ボタン
 */

import { useState, useRef, useEffect } from 'react';
import type { I18nMessages } from '@/client/lib/theme/i18n';

interface ChatInputProps {
  input: string;
  isLoading: boolean;
  onInputChange: (value: string) => void;
  onSubmit: () => void;
  messages_i18n: I18nMessages;
}

const MAX_ROWS = 3;
const LINE_HEIGHT = 24; // 1行の高さ（px）
const PADDING = 24; // 上下padding合計（py-3 = 12px * 2）

export function ChatInput({
  input,
  isLoading,
  onInputChange,
  onSubmit,
  messages_i18n,
}: ChatInputProps) {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const [isComposing, setIsComposing] = useState(false);

  // 動的リサイズ処理：入力内容に応じて高さを自動調整
  useEffect(() => {
    if (textareaRef.current) {
      // 一旦高さをリセットしてscrollHeightを正確に取得
      textareaRef.current.style.height = 'auto';
      const scrollHeight = textareaRef.current.scrollHeight;
      const maxHeight = MAX_ROWS * LINE_HEIGHT + PADDING;
      // scrollHeightを元に高さを設定（最大高さを超えないように）
      textareaRef.current.style.height = `${Math.min(scrollHeight, maxHeight)}px`;
    }
  }, [input]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    // IME変換中はEnterキーを無視
    if (e.key === 'Enter' && !e.shiftKey && !isComposing) {
      e.preventDefault();
      if (input.trim() && !isLoading) {
        onSubmit();
      }
    }
  };

  const handleCompositionStart = () => {
    setIsComposing(true);
  };

  const handleCompositionEnd = () => {
    setIsComposing(false);
  };

  return (
    <div className="border-t border-gray-200 bg-white px-4 py-3 md:px-4 md:py-4">
      {/* 入力エリア */}
      <div className="flex items-center space-x-2 md:space-x-2">
        <div className="flex-1 relative">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={e => onInputChange(e.target.value)}
            onKeyDown={handleKeyDown}
            onCompositionStart={handleCompositionStart}
            onCompositionEnd={handleCompositionEnd}
            placeholder={messages_i18n.placeholder}
            disabled={isLoading}
            rows={1}
            className="w-full px-4 py-3
                     border border-[#DDDDDD] rounded-[24px]
                     text-sm md:text-[15px] text-[#333333] placeholder:text-[#999999]
                     resize-none overflow-y-auto
                     focus:outline-none focus:ring-2 focus:ring-[#8B7AB8] focus:border-transparent
                     disabled:bg-gray-100 disabled:text-gray-500
                     transition-all duration-150"
            style={{
              minHeight: `${LINE_HEIGHT + PADDING}px`,
              maxHeight: `${MAX_ROWS * LINE_HEIGHT + PADDING}px`,
            }}
          />
        </div>

        {/* 送信ボタン（紫色の円形） */}
        <button
          onClick={onSubmit}
          disabled={!input.trim() || isLoading}
          className="flex-shrink-0 w-12 h-12
                   self-start
                   bg-[#8B7AB8]
                   rounded-full
                   flex items-center justify-center
                   transition-all duration-150
                   hover:bg-[#7A6AA7] hover:shadow-md
                   disabled:bg-gray-300 disabled:cursor-not-allowed
                   focus:outline-none focus:ring-2 focus:ring-[#8B7AB8] focus:ring-offset-2"
          aria-label={messages_i18n.send}
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            strokeWidth={2.5}
            stroke="white"
            className="w-6 h-6"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              d="M6 12L3.269 3.126A59.768 59.768 0 0121.485 12 59.77 59.77 0 013.27 20.876L5.999 12zm0 0h7.5"
            />
          </svg>
        </button>
      </div>

      {/* 注意文言（フッター） */}
      <div className="mt-3 px-1 space-y-0.5">
        <p className="text-[10px] text-gray-500 leading-relaxed">{messages_i18n.disclaimer1}</p>
        <p className="text-[10px] text-gray-500 leading-relaxed">{messages_i18n.disclaimer2}</p>
        <p className="text-[10px] text-gray-500 leading-relaxed">{messages_i18n.disclaimer3}</p>
      </div>

      {/* Powered by AI */}
      <div className="mt-2 px-1">
        <p className="text-[10px] text-gray-400 text-right">Powered by AI</p>
      </div>
    </div>
  );
}

