/**
 * i18n - Internationalization Support
 * タスク4.2: ブラウザ言語検知と多言語対応
 */

export type SupportedLocale = 'ja' | 'en' | 'zh' | 'ko';

export interface I18nMessages {
  placeholder: string;
  send: string;
  loading: string;
  error: string;
  retry: string;
  charLimitError: string;
  piiError: string;
  welcome: string;
}

const messages: Record<SupportedLocale, I18nMessages> = {
  ja: {
    placeholder: 'メッセージを入力してください',
    send: '送信',
    loading: '応答を生成中...',
    error: 'エラーが発生しました',
    retry: '再試行',
    charLimitError: '256文字以内で入力してください',
    piiError: '個人情報は入力しないでください',
    welcome:
      'こんにちは！ワールドマスターズゲームズ2027関西のサポートチャットです 🎉\n大会に関するご質問にAIがお答えします。\nメッセージを入力してください。',
  },
  en: {
    placeholder: 'Enter your message',
    send: 'Send',
    loading: 'Generating response...',
    error: 'An error occurred',
    retry: 'Retry',
    charLimitError: 'Please enter within 256 characters',
    piiError: 'Please do not enter personal information',
    welcome:
      'Hello! Welcome to World Masters Games 2027 Kansai Support Chat 🎉\nOur AI will answer your questions about the games.\nPlease enter your message.',
  },
  zh: {
    placeholder: '请输入消息',
    send: '发送',
    loading: '正在生成回复...',
    error: '发生错误',
    retry: '重试',
    charLimitError: '请在256个字符以内输入',
    piiError: '请勿输入个人信息',
    welcome:
      '您好！欢迎使用2027年世界大师运动会关西支持聊天 🎉\nAI将回答您关于大会的问题。\n请输入您的消息。',
  },
  ko: {
    placeholder: '메시지를 입력하세요',
    send: '전송',
    loading: '응답 생성 중...',
    error: '오류가 발생했습니다',
    retry: '재시도',
    charLimitError: '256자 이내로 입력해주세요',
    piiError: '개인정보를 입력하지 마세요',
    welcome:
      '안녕하세요! 2027 월드마스터즈게임 간사이 지원 챗봇입니다 🎉\nAI가 대회에 관한 질문에 답변해 드립니다.\n메시지를 입력해 주세요.',
  },
};

/**
 * ブラウザ言語を検知してサポート対象のロケールを返す
 */
export function detectBrowserLocale(): SupportedLocale {
  if (typeof window === 'undefined') {
    return 'ja'; // SSR時はデフォルト
  }

  const browserLang = navigator.language.toLowerCase();

  if (browserLang.startsWith('ja')) return 'ja';
  if (browserLang.startsWith('en')) return 'en';
  if (browserLang.startsWith('zh')) return 'zh';
  if (browserLang.startsWith('ko')) return 'ko';

  return 'ja'; // デフォルトは日本語
}

/**
 * ロケールに対応するメッセージを取得
 */
export function getMessages(locale: SupportedLocale): I18nMessages {
  return messages[locale];
}

'use client';

/**
 * Chat Window Component
 * チャットウィンドウ全体（ヘッダー、メッセージ表示エリア、入力エリア）
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';

interface ChatWindowProps {
  isOpen: boolean;
  onClose: () => void;
}

export function ChatWindow({ isOpen, onClose }: ChatWindowProps) {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI();

  if (!isOpen) return null;

  return (
    <>
      {/* モバイル用オーバーレイ（768px未満） */}
      <div
        className="fixed inset-0 bg-black/50 z-[1000] md:hidden animate-fadeIn"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* チャットウィンドウ */}
      <div
        className={`
          fixed z-[1001]
          flex flex-col
          bg-white
          shadow-2xl

          /* モバイル: 全画面表示 */
          bottom-0 left-0 right-0 top-0
          w-full h-full
          animate-slideUpMobile

          /* PC: 右下固定表示 */
          md:bottom-5 md:right-5 md:left-auto md:top-auto
          md:w-[400px] md:h-[600px]
          md:rounded-2xl
          md:animate-slideInDesktop
        `}
        role="dialog"
        aria-labelledby="chat-title"
        aria-modal="true"
      >
        {/* ヘッダー */}
        <div className="bg-[#E31E24] text-white px-4 py-3 md:py-4 flex items-center justify-between flex-shrink-0 md:rounded-t-2xl">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_65%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 id="chat-title" className="text-base md:text-lg font-bold leading-tight">
                WMG2027 サポートチャット
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                お気軽にご質問ください
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            onClick={onClose}
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center rounded-full hover:bg-white/20 transition-colors focus:outline-none focus:ring-2 focus:ring-white/50"
            aria-label="チャットを閉じる"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-6 h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* メッセージ表示エリア */}
        <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
          {/* ウェルカムメッセージ */}
          {messages.length === 0 && (
            <div className="mb-4">
              <div className="flex justify-start items-start">
                {/* ボットアイコン（WMGロゴ） */}
                <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                  <img
                    src="/wmg2027-logo.png"
                    alt="WMG2027 Logo"
                    className="w-full h-full object-cover object-[center_65%]"
                  />
                </div>

                {/* メッセージ */}
                <div className="flex flex-col items-start max-w-[85%]">
                  <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                    <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                      {messages_i18n.welcome}
                    </p>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* メッセージリスト */}
          {messages.map(message => (
            <ChatMessage key={message.id} message={message} />
          ))}

          {/* ローディングインジケータ */}
          {isLoading && <ChatLoadingIndicator />}

          {/* エラー表示 */}
          {error && (
            <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
              <p className="font-semibold">{messages_i18n.error}</p>
              <p className="text-sm mt-1">{error.message}</p>
              <button
                onClick={() => reload()}
                className="mt-2 text-sm underline hover:no-underline"
              >
                {messages_i18n.retry}
              </button>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* 入力エリア */}
        <div className="flex-shrink-0">
          <ChatInput
            input={input}
            isLoading={isLoading}
            onInputChange={handleInputChange}
            onSubmit={handleFormSubmit}
          />
        </div>
      </div>
    </>
  );
}

'use client';

/**
 * Chat Widget Frame
 * タスク4.1: チャットUIシェルとストリーミング入出力
 */

import { useChatUI } from '@/client/hooks/useChatUI';
import { ChatMessage, ChatLoadingIndicator } from './ChatMessage';
import { ChatInput } from './ChatInput';
import { clientLogger } from '@/server/lib/logger';

export function ChatWidgetFrame() {
  const {
    messages_i18n,
    messagesEndRef,
    messages,
    input,
    isLoading,
    error,
    reload,
    handleInputChange,
    handleFormSubmit,
  } = useChatUI({
    onError: err => {
      clientLogger.error('Chat error', err);
    },
  });

  return (
    <div className="flex flex-col h-full bg-white rounded-none md:rounded-lg shadow-none md:shadow-lg">
      {/* ヘッダー */}
      <div className="bg-[#E31E24] text-white p-3 md:p-4 rounded-none md:rounded-t-lg relative">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            {/* WMGロゴ */}
            <div className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-white flex items-center justify-center flex-shrink-0 p-1 overflow-hidden">
              <img
                src="/wmg2027-logo.png"
                alt="WMG2027 Logo"
                className="w-full h-full object-cover object-[center_65%]"
              />
            </div>

            {/* タイトル */}
            <div className="flex-1">
              <h2 className="text-base md:text-lg font-bold leading-tight">
                WMG2027 サポートチャット
              </h2>
              <p className="text-xs md:text-sm text-white/95 leading-tight">
                お気軽にご質問ください
              </p>
            </div>
          </div>

          {/* 閉じるボタン */}
          <button
            className="w-8 h-8 md:w-9 md:h-9 flex items-center justify-center text-white hover:bg-white/20 rounded-full transition-colors flex-shrink-0"
            aria-label="閉じる"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              strokeWidth={2.5}
              stroke="currentColor"
              className="w-5 h-5 md:w-6 md:h-6"
            >
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
      </div>

      {/* メッセージリスト */}
      <div className="flex-1 overflow-y-auto bg-gray-50 px-4 py-4 md:px-4 md:py-4">
        {/* ウェルカムメッセージ */}
        {messages.length === 0 && (
          <div className="mb-4">
            <div className="flex justify-start items-start">
              {/* ボットアイコン（WMGロゴ） */}
              <div className="flex-shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-white flex items-center justify-center mr-2 shadow-md p-1 overflow-hidden">
                <img
                  src="/wmg2027-logo.png"
                  alt="WMG2027 Logo"
                  className="w-full h-full object-cover object-[center_65%]"
                />
              </div>

              {/* メッセージ */}
              <div className="flex flex-col items-start max-w-[85%]">
                <div className="bg-white text-gray-800 rounded-2xl px-4 py-3 shadow-[0_2px_8px_rgba(0,0,0,0.1)]">
                  <p className="text-sm md:text-[15px] whitespace-pre-wrap break-words leading-relaxed">
                    {messages_i18n.welcome}
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* メッセージ表示（ChatMessageコンポーネントを使用） */}
        {messages.map(message => (
          <ChatMessage key={message.id} message={message} />
        ))}

        {/* ローディング表示（ChatLoadingIndicatorを使用） */}
        {isLoading && <ChatLoadingIndicator />}

        {/* エラー表示 */}
        {error && (
          <div className="bg-red-50 border border-red-200 text-red-800 p-3 rounded-lg mb-4">
            <p className="font-semibold">{messages_i18n.error}</p>
            <p className="text-sm mt-1">{error.message}</p>
            <button onClick={() => reload()} className="mt-2 text-sm underline hover:no-underline">
              {messages_i18n.retry}
            </button>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* 入力エリア */}
      <div className="flex-shrink-0">
        <ChatInput
          input={input}
          isLoading={isLoading}
          onInputChange={handleInputChange}
          onSubmit={handleFormSubmit}
        />
      </div>
    </div>
  );
}

