/**
 * ChatInput Component Unit Tests
 * Issue #112: Chat UIテスト追加
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { ChatInput } from '@/client/components/chat/ChatInput';

describe('ChatInput Component', () => {
  const mockOnInputChange = vi.fn();
  const mockOnSubmit = vi.fn();

  const defaultProps = {
    input: '',
    isLoading: false,
    onInputChange: mockOnInputChange,
    onSubmit: mockOnSubmit,
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('Rendering', () => {
    it('should render textarea with placeholder', () => {
      render(<ChatInput {...defaultProps} />);

      expect(screen.getByPlaceholderText('質問を入力してください')).toBeInTheDocument();
    });

    it('should render custom placeholder when provided', () => {
      render(<ChatInput {...defaultProps} placeholder="カスタムプレースホルダー" />);

      expect(screen.getByPlaceholderText('カスタムプレースホルダー')).toBeInTheDocument();
    });

    it('should render send button', () => {
      render(<ChatInput {...defaultProps} />);

      expect(screen.getByRole('button', { name: '送信' })).toBeInTheDocument();
    });

    it('should render "Powered by AI" footer', () => {
      render(<ChatInput {...defaultProps} />);

      expect(screen.getByText('Powered by AI')).toBeInTheDocument();
    });
  });

  describe('Input Handling', () => {
    it('should call onInputChange when typing', async () => {
      const user = userEvent.setup();
      render(<ChatInput {...defaultProps} />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');
      await user.type(textarea, 'Hello');

      // onInputChange should be called for each character
      expect(mockOnInputChange).toHaveBeenCalled();
    });

    it('should display current input value', () => {
      render(<ChatInput {...defaultProps} input="テスト入力" />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');
      expect(textarea).toHaveValue('テスト入力');
    });

    it('should be disabled when isLoading is true', () => {
      render(<ChatInput {...defaultProps} isLoading={true} />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');
      expect(textarea).toBeDisabled();
    });
  });

  describe('Submit Behavior', () => {
    it('should call onSubmit when send button is clicked with non-empty input', async () => {
      const user = userEvent.setup();
      render(<ChatInput {...defaultProps} input="テストメッセージ" />);

      const button = screen.getByRole('button', { name: '送信' });
      await user.click(button);

      expect(mockOnSubmit).toHaveBeenCalledTimes(1);
    });

    it('should not call onSubmit when input is empty', async () => {
      const user = userEvent.setup();
      render(<ChatInput {...defaultProps} input="" />);

      const button = screen.getByRole('button', { name: '送信' });
      await user.click(button);

      expect(mockOnSubmit).not.toHaveBeenCalled();
    });

    it('should not call onSubmit when input is whitespace only', async () => {
      const user = userEvent.setup();
      render(<ChatInput {...defaultProps} input="   " />);

      const button = screen.getByRole('button', { name: '送信' });
      await user.click(button);

      expect(mockOnSubmit).not.toHaveBeenCalled();
    });

    it('should call onSubmit when Enter key is pressed', () => {
      render(<ChatInput {...defaultProps} input="テストメッセージ" />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');
      fireEvent.keyDown(textarea, { key: 'Enter', shiftKey: false });

      expect(mockOnSubmit).toHaveBeenCalledTimes(1);
    });

    it('should not call onSubmit when Shift+Enter is pressed (new line)', () => {
      render(<ChatInput {...defaultProps} input="テストメッセージ" />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');
      fireEvent.keyDown(textarea, { key: 'Enter', shiftKey: true });

      expect(mockOnSubmit).not.toHaveBeenCalled();
    });

    it('should not call onSubmit while loading', async () => {
      const user = userEvent.setup();
      render(<ChatInput {...defaultProps} input="テストメッセージ" isLoading={true} />);

      const button = screen.getByRole('button', { name: '送信' });
      await user.click(button);

      expect(mockOnSubmit).not.toHaveBeenCalled();
    });
  });

  describe('Button State', () => {
    it('should disable button when input is empty', () => {
      render(<ChatInput {...defaultProps} input="" />);

      const button = screen.getByRole('button', { name: '送信' });
      expect(button).toBeDisabled();
    });

    it('should disable button when loading', () => {
      render(<ChatInput {...defaultProps} input="テスト" isLoading={true} />);

      const button = screen.getByRole('button', { name: '送信' });
      expect(button).toBeDisabled();
    });

    it('should enable button when input is non-empty and not loading', () => {
      render(<ChatInput {...defaultProps} input="テスト" isLoading={false} />);

      const button = screen.getByRole('button', { name: '送信' });
      expect(button).not.toBeDisabled();
    });
  });

  describe('IME Composition', () => {
    it('should not submit during IME composition', () => {
      render(<ChatInput {...defaultProps} input="てすと" />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');

      // Start composition
      fireEvent.compositionStart(textarea);

      // Try to submit with Enter
      fireEvent.keyDown(textarea, { key: 'Enter', shiftKey: false });

      // Should not submit during composition
      expect(mockOnSubmit).not.toHaveBeenCalled();

      // End composition
      fireEvent.compositionEnd(textarea);

      // Now Enter should work
      fireEvent.keyDown(textarea, { key: 'Enter', shiftKey: false });
      expect(mockOnSubmit).toHaveBeenCalledTimes(1);
    });
  });

  describe('Accessibility', () => {
    it('should have aria-label on send button', () => {
      render(<ChatInput {...defaultProps} />);

      const button = screen.getByRole('button', { name: '送信' });
      expect(button).toHaveAttribute('aria-label', '送信');
    });

    it('should be focusable', () => {
      render(<ChatInput {...defaultProps} />);

      const textarea = screen.getByPlaceholderText('質問を入力してください');
      textarea.focus();

      expect(document.activeElement).toBe(textarea);
    });
  });
});

